from dataclasses import dataclass
from datetime import date

@dataclass
class SourceArchiveRecord:
    service_name: str
    final_deployed_commit_sha: str
    repository_url: str
    archive_location: str        # e.g. git tag, S3 zip, internal mirror
    archived_date: date
    archived_by: str
    includes_deployment_configs: bool
    includes_infrastructure_code: bool
    read_only_enforced: bool

    def archive_tag(self) -> str:
        return f"archive/{self.service_name}/eol-{self.archived_date.strftime('%Y%m%d')}"

    def verification_command(self) -> str:
        return (
            f"git fetch origin {self.archive_tag()} && "
            f"git checkout {self.archive_tag()} -- "
            f"# verify HEAD matches {self.final_deployed_commit_sha[:8]}"
        )

    def is_complete(self) -> bool:
        return (
            bool(self.final_deployed_commit_sha)
            and bool(self.archive_location)
            and self.read_only_enforced
            and self.includes_deployment_configs
        )

from dataclasses import dataclass, field
from datetime import date

@dataclass
class ArchitectureDecisionRecord:
    decision_id: str              # e.g. "ADR-012"
    title: str
    date_decided: date
    decision_maker: str
    context: str                  # the situation that made the decision necessary
    considered_options: list[str] # alternatives that were evaluated
    chosen_option: str
    rationale: str                # why this option over the others
    trade_offs: str               # what was given up by choosing this option
    revisit_condition: str        # under what circumstance should this be reconsidered

    def to_archive_markdown(self) -> str:
        options_list = "\n".join(f"- {o}" for o in self.considered_options)
        return f"""## {self.decision_id}: {self.title}

**Date:** {self.date_decided}
**Decided by:** {self.decision_maker}

### Context
{self.context}

### Options Considered
{options_list}

### Decision
{self.chosen_option}

### Rationale
{self.rationale}

### Trade-offs
{self.trade_offs}

### Revisit Condition
{self.revisit_condition}
"""

@dataclass
class DecisionLog:
    service_name: str
    records: list[ArchitectureDecisionRecord] = field(default_factory=list)

    def add(self, record: ArchitectureDecisionRecord) -> None:
        self.records.append(record)

    def export_markdown(self) -> str:
        header = f"# Decision Log: {self.service_name}\n\n"
        return header + "\n".join(r.to_archive_markdown() for r in self.records)

    def decisions_about(self, topic: str) -> list[ArchitectureDecisionRecord]:
        topic_lower = topic.lower()
        return [r for r in self.records if topic_lower in r.title.lower() or topic_lower in r.context.lower()]

from dataclasses import dataclass, field
from datetime import datetime

@dataclass
class IncidentPostMortem:
    incident_id: str
    title: str
    severity: str           # "P1" | "P2" | "P3"
    started_at: datetime
    resolved_at: datetime
    affected_users: int | None
    timeline: list[str]     # chronological events
    root_cause: str
    contributing_factors: list[str]
    detection_gap: str      # what monitoring failed to catch it earlier
    mitigations_applied: list[str]
    corrective_actions_taken: list[str]
    claude_behaviour_relevant: bool   # True if model behaviour contributed to incident
    claude_behaviour_notes: str = ""  # details if model behaviour contributed

    def duration_minutes(self) -> int:
        return int((self.resolved_at - self.started_at).total_seconds() / 60)

    def archive_summary(self) -> str:
        claude_note = (
            f"\n**Claude behaviour relevance:** {self.claude_behaviour_notes}"
            if self.claude_behaviour_relevant else ""
        )
        return (
            f"## {self.incident_id}: {self.title} ({self.severity})\n"
            f"Duration: {self.duration_minutes()} minutes | "
            f"Affected users: {self.affected_users or 'unknown'}\n"
            f"Root cause: {self.root_cause}{claude_note}"
        )

@dataclass
class IncidentHistoryArchive:
    service_name: str
    incidents: list[IncidentPostMortem] = field(default_factory=list)

    def claude_relevant_incidents(self) -> list[IncidentPostMortem]:
        return [i for i in self.incidents if i.claude_behaviour_relevant]

    def by_severity(self, severity: str) -> list[IncidentPostMortem]:
        return [i for i in self.incidents if i.severity == severity]

    def export_for_archive(self) -> str:
        lines = [f"# Incident History: {self.service_name}\n"]
        lines.append(f"Total incidents: {len(self.incidents)}")
        lines.append(f"Claude-behaviour-relevant: {len(self.claude_relevant_incidents())}\n")
        for incident in sorted(self.incidents, key=lambda i: i.started_at):
            lines.append(incident.archive_summary())
        return "\n".join(lines)

from dataclasses import dataclass, field

@dataclass
class ArchivalCompleteness:
    service_name: str
    artefacts: list["ArchivalArtefact"] = field(default_factory=list)
    prompt_archive_has_evals: bool = False
    decision_log_entry_count: int = 0
    knowledge_transfer_session_held: bool = False

    def before_teardown_complete(self) -> bool:
        from_main_module import ArchivalUrgency  # ArchivalArtefact imported from earlier
        # Check all BEFORE_TEARDOWN artefacts are complete
        critical = [
            a for a in self.artefacts
            if a.urgency == ArchivalUrgency.BEFORE_TEARDOWN
        ]
        return all(a.is_complete for a in critical)

    def prompt_archive_complete(self) -> bool:
        return self.prompt_archive_has_evals

    def decision_log_adequate(self, min_entries: int = 3) -> bool:
        return self.decision_log_entry_count >= min_entries

    def gate_status(self) -> str:
        issues = []
        if not self.prompt_archive_has_evals:
            issues.append("prompt archive missing evaluation suite")
        if not self.decision_log_adequate():
            issues.append(f"decision log has < 3 entries ({self.decision_log_entry_count})")
        if not self.knowledge_transfer_session_held:
            issues.append("knowledge transfer session not confirmed")
        if issues:
            return f"INCOMPLETE: {'; '.join(issues)}"
        return "COMPLETE: archival gate passed"
